esqlQuery.esql:
FROM metrics-influxdb.otel-*
// HTTP API requests with response code/status
| WHERE COALESCE(metrics.http_api_requests_total, http_api_requests_total) IS NOT NULL
// Aggregate total and error counts per host (status != 2XX = errors)
| STATS total = SUM(COALESCE(metrics.http_api_requests_total, http_api_requests_total)),
    errors = SUM(COALESCE(metrics.http_api_requests_total, http_api_requests_total))
      WHERE COALESCE(attributes.status, status) != "2XX"
  BY host.name
// Minimum sample size to avoid noisy low-traffic hosts
| WHERE total > 10
// Calculate error rate as percentage
| EVAL error_rate_pct = ROUND(errors / total * 100.0, 2)
// Alert threshold: adjust for your environment (e.g. 5%)
| WHERE error_rate_pct > 5.0
| SORT error_rate_pct DESC
| LIMIT 10
